// 16 spike polygons around the cap edge.
// Spike base at r≈24 (4px wide), tip at r=34. Rotated n×22.5° around (40,40).
const SPIKE_COUNT = 16
const spikes = Array.from({ length: SPIKE_COUNT }, (_, i) => {
  const angle = (i * 360) / SPIKE_COUNT
  return (
    <polygon
      key={i}
      points="38,16 42,16 40,7"
      transform={`rotate(${angle}, 40, 40)`}
      fill="currentColor"
      opacity={i % 2 === 0 ? 0.75 : 0.45}
      style={{ shapeRendering: 'crispEdges' } as React.CSSProperties}
    />
  )
})

function CapSpinner() {
  return (
    <svg
      viewBox="0 0 80 80"
      className={s.capSvg}
      aria-hidden="true"
      style={{ color: 'var(--accent, #f29774)', overflow: 'visible' }}
    >
      <g className={s.capGroup} style={{ transformOrigin: '40px 40px' } as React.CSSProperties}>
        {/* Spikes */}
        {spikes}

        {/* Cap rim ring */}
        <circle cx="40" cy="40" r="23" fill="none" stroke="currentColor" strokeWidth="1.5" opacity="0.25" style={{ shapeRendering: 'crispEdges' } as React.CSSProperties} />

        {/* Cap body */}
        <circle cx="40" cy="40" r="21" fill="currentColor" style={{ shapeRendering: 'crispEdges' } as React.CSSProperties} />

        {/* Brand T-mark (logo-61.svg) — scaled to fit cap body, cutout fill */}
        <g transform="translate(29, 31.3) scale(0.187)" fill="var(--bg, #090909)">
          <path fillRule="evenodd" clipRule="evenodd" d={LOGO_PATH} />
        </g>
      </g>
    </svg>
  )
}

export default function LoadingScreen() {
  const [show, setShow] = useState(false)
  const [exit, setExit] = useState(false)
  const phrases: string[] = (typeof window !== 'undefined' && (window as unknown as Record<string, unknown>)['__THREEP_LOADING_PHRASES__'] as string[]) || DEFAULT_PHRASES
  const [phraseIdx, setPhraseIdx] = useState(0)
  const [phraseVisible, setPhraseVisible] = useState(true)
  const cycleRef = useRef<ReturnType<typeof setInterval> | null>(null)

  useEffect(() => {
    try {
      if (sessionStorage.getItem('threep-booted')) return
      sessionStorage.setItem('threep-booted', '1')
    } catch {
      return
    }

    setShow(true)

    let minPassed = false
    let pageDone = false
    let dismissed = false

    function dismiss() {
      if (dismissed) return
      dismissed = true
      setExit(true)
      setTimeout(() => setShow(false), 580)
    }

    function onPageReady() {
      pageDone = true
      if (minPassed) dismiss()
    }

    // Min on-screen time so the brand beat lands; max cap so a hanging
    // resource can never leave the loader stuck.
    const minTimer = setTimeout(() => {
      minPassed = true
      if (pageDone) dismiss()
    }, 1200)
    // Потолок повыше: на медленном соединении карточкам каталога (priority-
    // изображения первого ряда) нужно успеть догрузиться до window.load.
    const maxTimer = setTimeout(dismiss, 6500)

    if (document.readyState === 'complete') {
      onPageReady()
    } else {
      window.addEventListener('load', onPageReady, { once: true })
    }

    return () => {
      clearTimeout(minTimer)
      clearTimeout(maxTimer)
      window.removeEventListener('load', onPageReady)
    }
  }, [])

  useEffect(() => {
    if (!show) return
    cycleRef.current = setInterval(() => {
      setPhraseVisible(false)
      setTimeout(() => {
        setPhraseIdx(i => (i + 1) % phrases.length)
        setPhraseVisible(true)
      }, 280)
    }, 1800)
    return () => {
      if (cycleRef.current) clearInterval(cycleRef.current)
    }
  }, [show, phrases.length])

  if (!show) return null

  return (
    <div className={`${s.screen} ${exit ? s.exit : ''}`} aria-hidden="true">
      <div className={s.scanlines} />
      <div className={s.vignette} />
      <div className={s.spinner}>
        <div className={s.string} />
        <CapSpinner />
        <div className={s.stringBottom} />
      </div>
      <div className={`${s.sub} ${phraseVisible ? s.subVisible : s.subHidden}`}>{phrases[phraseIdx]}</div>
    </div>
  )
}
